import tarfile
import os


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                # Check for absolute path or path traversal
                if member.name.startswith('/') or '..' in member.name:
                    return False
            # Ensure the destination path is absolute and normalized
            dest_path_abs = os.path.abspath(dest_path)
            # Extract all members safely
            tar.extractall(path=dest_path_abs)
        return True
    except Exception:
        return False

