import base64
import json

def confirmAuth(headers):
    auth_token_str = headers.get('AuthToken')
    if not auth_token_str:
        return None
    try:
        decoded_bytes = base64.b64decode(auth_token_str)
        decoded_str = decoded_bytes.decode('utf-8')
        token_obj = json.loads(decoded_str)
    except (UnicodeDecodeError, ValueError, json.JSONDecodeError):
        return None
    return token_obj

